package chapter04;

public class f_IfExample {
	public static void main(String[] args) {
		//조건문 : if문
		/* 
		  if(조건식){
		       실행문A
		      }
		   1.  조건식이 true면 실행문A가 실행
		    2. 조건식이 false이면 실행문 A가 실행X 실행문B
		    */
		
		boolean b=true;
		if(b) {
			System.out.println("if ()안의 결과가 true인 경우에만 실행 ");
		}
		System.out.println("코드의 끝줄 실행");
		// 조건식이 true가 될 때 실행해야 할 문장이 하나밖에 없다면 생략할 수 있음
		if(true)
			System.out.println("If 블록안에 포함되는 문장");
		System.out.println("블록 밖의 문장");                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
		
		if(true)	System.out.println("If 블록안의 문장");
		
		if(true)
			System.out.println("If 블록안의 문장1");
		    System.out.println("If 블록안의 문장2");
		
		    int score=93;
		    
		    if (score>=90) {
		    	System.out.println("점수가 90점 이상입니다.");
		    	System.out.println("등급은 A입니다.");
		    	
		    	if (score<90) {
		    		System.out.println("점수가 90점 이하입니다.");
		    		System.out.println("등급은 B입니다.");
		    }
		}
	}
}

